INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-01','Containers on non-cellular ships','Annex 1','Containers carried on deck/hatches of ships not specially designed/fitted for containers.','Stow fore-and-aft; lashings (wire/chain); timber shoring <=2m; secure to prevent sliding/tipping.','(deck containers — rare in sub-35k niche)',1) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-02','Portable tanks (tank-containers)','Annex 2','Tank not permanently secured, >450 L, external stabilizing members; ISO or non-ISO frame.','Lashing angle <=25 deg sliding, 45-60 deg tipping; CSC compliance; IMDG if DG.','(tank-containers)',2) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-03','Portable receptacles','Annex 3','Receptacle (not a portable tank), capacity <= 1,000 L; cylinders, frames of cylinders.','Dunnage off steel deck; stow upright for liquefied gas; box/crib, brace, chock.','(gas cylinders, receptacles)',3) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-04','Wheel-based (rolling) cargoes','Annex 4','Cargoes on wheels/tracks: buses, tractors, earth-movers, roll-trailers (excl. road trailers/trains).','Marked securing points; brakes set; chocks; lashings >= steel chain/wire; stow fore-and-aft.','Shredded Tyres',4) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-05','Heavy cargo items','Annex 5','Heavy items such as locomotives, transformers, etc.','CoG + bedding info; timber spread load; lashing 25 deg slide / 45-60 deg tip; shoring if large angles.','Project Cargo, Marble Blocks, Granite Blocks',5) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-06','Coiled sheet steel','Annex 6','Coiled sheet steel stowed on the round (typically >10 t per coil).','Bottom stow, axes fore-and-aft, dunnage athwartships, locking coils, wedges, top-tier lashing.','Steel Coils, Hot Rolled Coils',6) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-07','Heavy metal products','Annex 7','Any heavy metal item: bars, pipes, rods, plates, billets, wire coils, etc.','Compact side-to-side, no voids; do not exceed deck/tank-top load; shore every frame >=1m; top-layer lashing.','Steel Rebars, Steel Bars, Steel Billets, Wire Rod in Coils, Steel Plates, Steel Sheets, Steel Slabs, Steel Products, Steel Debars, DBIC',7) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-08','Anchor chains','Annex 8','Anchor chains in bundles or continuous lengths.','Never on bare metal — wooden ceiling/dunnage; tight stow; top layer lashed both sides.','(anchor chains)',8) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-09','Metal scrap in bulk','Annex 9','Metal scrap difficult to stow compactly (excl. borings/shavings/turnings — those are IMSBC).','Protect side plating/pipes; heavy first; no voids; lash/overstow heavy pieces; watch tank-top load.','(scrap metal)',9) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-10','Flexible intermediate bulk containers (FIBC)','Annex 10','Flexible portable packaging for solids, capacity <= 3 m3 (3,000 L); one-way or multi-trip.','Wide hatches; stow tight from sides to centre; chock voids in centre; gratings/plywood + wire lashings.','Bagged Cargo (big bags)',10) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-11','Logs (under-deck stow)','Annex 11','Under-deck stowage of logs; bilge/stability/ballast precautions.','Pre-stow plan; heaviest first; compact fore-and-aft, fill athwartship voids; bilge & stability checks.','Logs',11) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
INSERT INTO public.css_categories (code,name,css_annex,definition,securing_trigger,market_aliases,sort_order) VALUES ('CSS-12','Unit loads','Annex 12','Packages on a pallet/load board, in a pallet box, or permanently secured in a sling.','Clean flush deck; block stow no voids; gratings/plywood + wire lashings; check pallet strength if tiered.','Bagged Cargo, Sugar (bags), MDF Boards, Chipboards, General Cargo, Mixed BB',12) ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, css_annex=EXCLUDED.css_annex, definition=EXCLUDED.definition, securing_trigger=EXCLUDED.securing_trigger, market_aliases=EXCLUDED.market_aliases;
