-- ════════════════════════════════════════════════════════════════════
-- Cargo classification — Part 1 seed (from MASTER workbook v2)  · append-only
--
-- Authoritative reference data seeded from
-- ArabShipBroker_MASTER_Cargo_Classification_Map_v2.xlsx:
--   • imsbc_codes      — 258 BCSN names + group (A/B/C/"A and B") + UN
--   • css_categories   — 12 CSS categories (+ annex + market aliases)
--   • grain_list       — Grain Code commodities
--   • commodity_map    — 85-row resolver dictionary (market_name → regime/code/
--                        group), dual-form flagged, plausible_regimes seeded
--
-- Depends on …000700 (enum, tables, commodities extension). Firewall untouched —
-- pure reference/lookup data, no counterparty contact. Idempotent (ON CONFLICT).
-- ════════════════════════════════════════════════════════════════════

-- imsbc_codes (258 BCSN)

ALTER TABLE public.css_categories ADD COLUMN IF NOT EXISTS css_annex text, ADD COLUMN IF NOT EXISTS market_aliases text;
-- css_categories (12)

-- grain_list (authoritative from workbook)

CREATE TABLE IF NOT EXISTS public.commodity_map (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  market_name text NOT NULL UNIQUE,
  regime public.cargo_regime_enum NOT NULL,
  code text,
  group_cat text,
  is_dual_form boolean NOT NULL DEFAULT false,
  plausible_regimes public.cargo_regime_enum[] NOT NULL DEFAULT '{}',
  note text,
  is_active boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now()
);
ALTER TABLE public.commodity_map ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "commodity_map read" ON public.commodity_map;
CREATE POLICY "commodity_map read" ON public.commodity_map FOR SELECT TO anon, authenticated USING (true);
GRANT SELECT ON public.commodity_map TO anon, authenticated;
-- commodity_map (resolver dictionary)
